#include <stdio.h>
#include <string.h>
#define MOD 151109
int maxMines, ways;
int M, N;
char grid[25][25];
void backtrack(int x, int y, int mines, int mask) {
    if (y == N) {
        x++;
        y = 0;
    }
    if (x == M) {
        if (mines > maxMines) {
            maxMines = mines;
            ways = 1;
        } else if (mines == maxMines) {
            ways = (ways + 1) % MOD;
        }
        return;
    }
    if (grid[x][y] == '.') {
        if ((mask & (1 << (x * N + y))) == 0 && (x == 0 || grid[x-1][y] != 'M') && (y == 0 || grid[x][y-1] != 'M')) {
            grid[x][y] = 'M';
            backtrack(x, y + 1, mines + 1, mask | (1 << (x * N + y)));
            grid[x][y] = '.';
        }
        backtrack(x, y + 1, mines, mask);
    } else {
        backtrack(x, y + 1, mines, mask);
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &M, &N);
        for (int i = 0; i < M; i++) {
            scanf("%s", grid[i]);
        }
        maxMines = 0;
        ways = 0;
        backtrack(0, 0, 0, 0);
        printf("%d %d\n", maxMines, ways);
    }
    return 0;
}

