import java.util.Scanner;
public class Main {
    static final int MOD = 151109;
    static int maxMines, ways;
    static int M, N;
    static char[][] grid;
    public static void backtrack(int x, int y, int mines, int mask) {
        if (y == N) {
            x++;
            y = 0;
        }
        if (x == M) {
            if (mines > maxMines) {
                maxMines = mines;
                ways = 1;
            } else if (mines == maxMines) {
                ways = (ways + 1) % MOD;
            }
            return;
        }
        if (grid[x][y] == '.') {
            if ((mask & (1 << (x * N + y))) == 0 && (x == 0 || y == 0 || grid[x-1][y] != 'M' && grid[x][y-1] != 'M')) {
                grid[x][y] = 'M';
                backtrack(x, y + 1, mines + 1, mask | (1 << (x * N + y)));
                grid[x][y] = '.';
            }
            backtrack(x, y + 1, mines, mask);
        } else {
            backtrack(x, y + 1, mines, mask);
        }
